const items = $input.all();
const buildItems = $('Build prompt').all();

return items.map((item, i) => {
  const raw = item.json.content[0].text;
  const html = raw.replace(/^```html\n/, '').replace(/\n```$/, '');
  const config = buildItems[i]?.json;
  const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

  const topStoryMatch = raw.match(/TOP_STORY_START\n(.*?)\n(.*?)\n(.*?)\nTOP_STORY_END/s);

  let slackSummary;
  if (topStoryMatch) {
    const title = topStoryMatch[1].trim();
    const url = topStoryMatch[2].trim();
    const summary = topStoryMatch[3].trim();
    slackSummary = `*${config.topic} Weekly Digest — Week of ${today}*\n\n*Top story:* <${url}|${title}>\n${summary}\n\n_Full digest sent to ${config.email} — check your inbox for the complete report._`;
  } else {
    const linkMatch = html.match(/<a[^>]+href="([^"]+)"[^>]*>([^<]+)<\/a>/);
    const firstLink = linkMatch ? { url: linkMatch[1], title: linkMatch[2] } : null;
    slackSummary = firstLink
      ? `*${config.topic} Weekly Digest — Week of ${today}*\n\n*Top story:* <${firstLink.url}|${firstLink.title}>\n\n_Full digest sent to ${config.email} — check your inbox for the complete report._`
      : `*${config.topic} Weekly Digest — Week of ${today}*\n\nYour digest is ready.\n\n_Full digest sent to ${config.email} — check your inbox._`;
  }

  const cleanHtml = html.replace(/TOP_STORY_START[\s\S]*?TOP_STORY_END/g, '').trim();

  return { json: {
    htmlDigest: cleanHtml,
    slackSummary,
    email: config.email,
    channel: config.channel,
    topic: config.topic
  }};
});

const items = $input.all();
return items.map(item => {
  const {
    topic, email, channel, regulations, regulation_section_title,
    companies, watchlist, searchResults, trusted_sources
  } = item.json;
  const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
  const hasRegulations = regulations && regulations.trim().length > 0;
  const prompt = `You are a research analyst producing a weekly digest for a product manager working in the ${topic} space.
You will be given a watchlist containing industries, companies, regulations, and trusted sources. Use these as context to guide your research and analysis.
Produce the digest in exactly this structure using the search results provided. Return ONLY valid HTML — no markdown, no code fences, no preamble. Use inline styles, max-width 640px, font-family Arial, background #ffffff.
Watchlist context: ${watchlist}
---
${topic} Weekly Digest — Week of ${today}
{2 sentence themed summary of the week}
---
${hasRegulations ? `${regulation_section_title} to watch
{1 single most urgent regulation or upcoming deadline this week from: ${regulations}}
---` : ''}
Company headlines and feature launches
For each of 3 items:
{Headline title — source url}
Summary: {3 sentences explaining what happened}
What we can learn: {2 sentences on why this matters for your product}
---
${hasRegulations ? `${regulation_section_title} headlines
For each of 2 items:
{Headline title — source url}
Summary: {3 sentences explaining what happened}
What we can learn: {2 sentences on why this matters for your product}
---` : ''}
Trend alert
For each of 2 items:
{2 sentence trend description + link to explore more}
---
Market gap callout
{2-3 sentences identifying something customers are asking for that no vendor is solving well yet. Be specific.}
Sources: {1-2 links}
---
Emerging customer pain
{2-3 sentences on what ${topic} practitioners are actively frustrated about this week.}
Sources: {1-2 links}
---
PM question of the week
{1 single strategic question worth sitting with this week, grounded in something specific from this digest}
---
Rules:
- Always include real links to sources from the search results
- Never fabricate headlines, URLs, or statistics
- If a section has insufficient real content, reduce items rather than invent
- Keep the tone analytical and direct, not journalistic
- Write from the perspective of a product manager, not a journalist
- Focus research on the ${topic} industry
- Pay particular attention to these companies: ${companies}
${hasRegulations ? `- Monitor these specific regulations: ${regulations}` : '- Skip all regulation sections entirely'}
- Prioritise content from these trusted sources: ${trusted_sources}
- At the very bottom of the email, add a small footer with this exact text in a small gray font: "To unsubscribe, visit [https://ellen-s.n8n.irn.hk/form/137d637e-73f7-4d31-a3a4-5c5e51acd059]"
---
After the closing </html> tag, add this block in plain text exactly as shown.
This MUST use the same article as the first item under "Company headlines and feature launches".
Do not add any extra lines, labels, or punctuation inside the block.

TOP_STORY_START
{Title of the first company headline — plain text only, no URL}
{Full URL of that article — must start with https:// and come from the search results}
{2 sentence summary of why this story matters for a product manager}
TOP_STORY_END

Search results:
${searchResults}`;
  return { json: { prompt, email, channel, topic } };
});

const items = $input.all();
const watchlistItems = $('Merge watchlist').all();

return items.map((item, i) => {
  const results = item.json.results || [];
  const config = watchlistItems[i]?.json || watchlistItems[0].json;

  const searchText = results.map((r, i) =>
    `[${i+1}] ${r.title}\n${r.url}\n${r.content || r.snippet || ''}`
  ).join('\n\n');

  return { json: {
    topic: config.topic,
    email: config.email,
    channel: config.channel,
    trusted_sources: config.trusted_sources,
    regulations: config.regulations,
    regulation_section_title: config.regulation_section_title,
    companies: config.companies,
    watchlist: config.watchlist,
    searchResults: searchText
  }};
});

const rows = $input.all();

return rows.flatMap(row => {
  const industries = row.json['Industries'].split(',').map(i => i.trim());
  const email = row.json['Email'];
  const channel = row.json['Slack channel'] || null;

  return industries.map(topic => ({
    json: { topic, email, channel }
  }));
});

const form = $input.first().json;
const selected = form['Industries'] || [];
const other = form['Other Industry'] ? [form['Other Industry']] : [];
const allIndustries = [...selected, ...other].join(', ');

return [{ json: {
  email: form['Your email'],
  channel: form['Slack channel id'] || '',
  industries: allIndustries,
  active: 'Yes'
}}];

const watchlistItems = $input.all();
const splitItems = $('Split industries').all();

return splitItems.map((splitItem) => {
  const split = splitItem.json;

  const matchedRow = watchlistItems.find(w => 
    w.json['Industry']?.toLowerCase() === split.topic?.toLowerCase()
  );
  const watchlist = matchedRow?.json || {};

  const userCompanies = split.companies 
    ? split.companies.split(',').map(c => c.trim()) 
    : [];

  const sheetCompanies = watchlist['Companies'] 
    ? watchlist['Companies'].split(',').map(c => c.trim()) 
    : [];

  const allCompanies = [...new Set([...sheetCompanies, ...userCompanies])];
  const trusted_sources = watchlist['Trusted Sources'] || 'techcrunch.com, reuters.com, bloomberg.com, wired.com';
  const regulations = watchlist['Regulations'] || '';
  const regulation_section_title = watchlist['Regulation Title'] || '';

  return {
    json: {
      topic: split.topic,
      email: split.email,
      channel: split.channel,
      trusted_sources,
      regulations,
      regulation_section_title,
      companies: allCompanies.join(', '),
      watchlist: `Industry: ${split.topic}. Companies: ${allCompanies.join(', ') || 'none'}. Regulations: ${regulations || 'none'}. Trusted sources: ${trusted_sources}.`
    }
  };
});
